#include <memory>

class Widget {};

void processWidget(Widget* widget) { // Compliant: raw pointer for observation
  if (widget) {
    widget->doSomething();
  }
}

void analyzeData(const Data& data) { // Compliant: reference for non-null observation
  data.process();
}

void takeOwnership(std::unique_ptr<Data> data) { // Compliant: takes ownership
  storedData = std::move(data);
}
